=Extract a structured founder profile from the following input.

RAW INPUT:
{{ $('Validate Input').item.json.raw_input }}

EXISTING PROFILE (partial — update only fields where new input provides better data):
{{ JSON.stringify($('Load Existing Profile').item.json ?? {}) }}

Return the complete profile JSON object.

parameters.jsCode:
const raw = $input.item.json;
const userId = $('Validate Input').item.json.user_id;

let text = '';
if (raw.content && Array.isArray(raw.content)) {
  text = raw.content.filter(b => b.type === 'text').map(b => b.text).join('');
} else {
  throw new Error('Unexpected Claude response: ' + JSON.stringify(raw).substring(0, 200));
}

const cleaned = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let profile;
try {
  profile = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude profile JSON: ' + e.message + '\nSnippet: ' + cleaned.substring(0, 300));
}

const required = ['company_name', 'niche', 'icp_summary', 'core_offer', 'tone', 'profile_complete'];
for (const k of required) {
  if (!(k in profile)) throw new Error('Missing required key: ' + k);
}

return [{ json: { user_id: userId, profile } }];

